static int32_t LmsConstTimeMemCmp(const uint8_t *a, const uint8_t *b, size_t len)
{
    volatile uint8_t diff = 0;
    for (size_t i = 0; i < len; i++) {
        diff |= a[i] ^ b[i];
    }
    /* Use != 0 instead of implicit conversion to ensure non-zero result */
    return (diff != 0) ? 1 : 0;
}
